:\"image/jpeg\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:3:\"3.5\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:16:\"PENTAX Optio M60\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:10:\"1243339070\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:3:\"6.3\";s:3:\"iso\";s:3:\"800\";s:13:\"shutter_speed\";s:5:\"0.025\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"1\";s:8:\"keywords\";a:0:{}}}'),(455,48,'_edit_lock','1756716547:3'),(443,88,'_menu_item_xfn',''),(205,10,'mfn-page-items-seo','Heading + icons\r\n\r\n<h1 style=\"color: #fff;\">Welcome to<br>Chambers Inc Website</h1>\r\n[divider height=\"40\"]\r\n\r\ncenter\r\n\r\n#252c2d\r\n\r\nno-repeat;center top;;\r\n\r\n20px\r\n\r\n10px 10px 10px\r\n\r\nzoomIn\r\n\r\nHeading + desc\r\n\r\n<h3>Kevin Wilkinson, Ex Tresu U.K</h3>\r\n\r\nno-repeat;center top;;\r\n\r\n20px\r\n\r\nDesc\r\n\r\n<h6> This site is dedicated to latest developments available for Chambered Doctor Blade Systems & Anilox Roller Technology in the UK.\r\nI offer a range of services to cater for individual needs  at competitive prices:\r\n<br />\r\nTroubleshooting on existing chamber & anilox roller systems specialist knowledge: Heidelberg, Komori, KBA, Man Roland & Mitsubishi. (Any chamber system, offset or flexo). Conversions from existing metering roll systems </h6>\r\n\r\nno-repeat;center top;;\r\n\r\n20px\r\n\r\nDesc\r\n\r\n<h5>Quality</h5>\r\n<p>  If you feel your system is past its best  and becoming inefficient. Non corrosive lightweight Stainless Steel replacement chambers can be designed for all sizes and all makes of press.\r\n<br />\r\nLight weight laser engraved ceramic anilox rollers, using the latest screen technology. Designed too give maximum efficiency with less blocking. Cell structure and line count to suite product need. </p>\r\n\r\nno-repeat;center top;;\r\n\r\nDesc\r\n\r\n<h5>Service Visits</h5>\r\n<p>Specialised Anilox Roller Cleaning Service: Onsite chemically cleaned, during a service visit.\r\nPeristaltic Circulators: fully automatic cleaning, temperature controlled. Eco-friendly roller and chamber cleaning system.\r\n</br>\r\nA complete range of Doctor Blade to suite individual needs.\r\n</br>\r\nThe new poly/steel combination is cleaning up the industry.\r\n\r\nAn alternative end seal arrangement,to fit a Tresu D2. Full range of impregnated felt seal to suite all H&B chamber systems\r\n</p>\r\n\r\nno-repeat;center top;;\r\n\r\nHeading\r\n\r\n<h3></h3>\r\n\r\nno-repeat;center top;;\r\n\r\n20px\r\n\r\nhttp://www.chambers-inc.co.uk/wp-content/uploads/2015/12/PROD_TRESU-FlexiPrint-IMW-E-Line-Chamber-Doctor-Blade_7by5-3.png\r\n\r\ncenter\r\n\r\n'),(432,10,'mfn-meta-seo-title','Chambers Inc Ltd'),(433,86,'_wp_attached_file','2015/12/Chambers-Inc-IMG_7083.jpg'),(434,86,'_wp_attachment_metadata','a:5:{s:5:\"width\";i:1920;s:6:\"height\";i:1280;s:4:\"file\";s:33:\"2015/12/Chambers-Inc-IMG_7083.jpg\";s:5:\"sizes\";a:16:{s:9:\"thumbnail\";a:4:{s:4:\"file\";s:33:\"Chambers-Inc-IMG_7083-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:6:\"medium\";a:4:{s:4:\"file\";s:33:\"Chambers-Inc-IMG_7083-300x200.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:200;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:12:\"medium_large\";a:4:{s:4:\"file\";s:33:\"Chambers-Inc-IMG_7083-768x512.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:512;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:5:\"large\";a:4:{s:4:\"file\";s:34:\"Chambers-Inc-IMG_7083-1024x683.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:683;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:14:\"post-thumbnail\";a:4:{s:4:\"file\";s:33:\"Chambers-Inc-IMG_7083-219x146.jpg\";s:5:\"width\";i:219;s:6:\"height\";i:146;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:5:\"50x50\";a:4:{s:4:\"file\";s:31:\"Chambers-Inc-IMG_7083-50x33.jpg\";s:5:\"width\";i:50;s:6:\"height\";i:33;s:9:\"mime-type\";s:10:\"image/jpeg\";}s:14:\"clients-slider\";a:4:{s:4:\"file\";s:32:\"Chambers-Inc-IMG_7083-113x75.jpg\";s:5:\"width\";i:113;s:6:\"height\";i:75;s:9: