\n#{{block.view_id}} p {\r\n	margin: 0;\r\n}\r\n/*subscribe form styles*/\r\n#{{block.view_id}} .scsFormShell {\r\n	padding: 50px 0;\r\n}\r\n#{{block.view_id}} .scsFormShell .scsElInput,\r\n#{{block.view_id}} .scsFormShell .scsInputShell {\r\n	width: 100%;\r\n}\r\n#{{block.view_id}} .scsFormShell .scsElInput {\r\n	padding-right: 15px;\r\n  	padding-bottom: 5px;\r\n}\r\n#{{block.view_id}} .scsFormInput {\r\n	width: 100%;\r\n  	padding: 5px 20px;\r\n  	height: 40px;\r\n  	color: #b0b0b0;\r\n  	border: 1px solid #a9a9a9;\r\n  	font-size: 11px;\r\n  	font-weight: 700;\r\n  	box-shadow: 0px 1px 2px rgba(0, 0, 0, 0.2);\r\n  	transition: border 0.2s linear 0s, box-shadow 0.2s linear 0s;\r\n}\r\n#{{block.view_id}} .scsFormInput:focus,\r\n#{{block.view_id}} .scsFormInput:hover {\r\n	border: 1px solid #818181;\r\n}\r\n#{{block.view_id}} .scsFormInput[type=\"submit\"] {\r\n	border: 1px solid #901b08;\r\n	background-color: #cc361d;\r\n	color: #FFF;\r\n	text-shadow: 0 1px 0 #881a07;\r\n	box-shadow: 0px 1px 2px rgba(0, 0, 0, 0.2), 0 1px 0 #e45f48 inset;\r\n  	line-height: 20px;\r\n}\r\n#{{block.view_id}} .scsFormInput[type=\"submit\"]:hover {background-color: #d3381e;}\r\n#{{block.view_id}} .scsFormInput[type=\"submit\"]:focus {background-color: #bb311a;}\r\n/*main styles*/','mf-subscribe.jpg',4,1,0,'2015-09-04 19:25:20'),(5,1,5,'7jbXe3rZ','MF Footer',0,'','<div class=\"scsCoverOverlay\"></div>\r\n<div class=\"container scsContent\">\r\n	<div class=\"row\">\r\n  		<div class=\"scsEl scsTopDelimiter col-sm-12\" data-el=\"delimiter\" data-color=\"#dbdbdb\">\r\n      		<div class=\"scsDelimContent\" style=\"background-color: #dbdbdb;\"></div>\r\n      	</div>\r\n  	</div>\r\n  	<div class=\"row\">\r\n  		<div class=\"col-sm-6 scsFooterColLeft\">\r\n      		<div class=\"scsEl\" data-el=\"txt\">\r\n      			<p><span style=\"color: rgb(169, 169, 169);\" data-mce-style=\"color: #a9a9a9;\">Copyright В© 2015 <span style=\"color: rgb(86, 86, 86);\" data-mce-style=\"color: #565656;\"><stron